#include <stdio.h>
#include <limits.h>

int min(int a, int b) { return a < b ? a : b; }

int main() {
    int S, G, Q, R, D;
    scanf("%d %d %d %d %d", &S, &G, &Q, &R, &D);
    int q;
    scanf("%d", &q);
    while (q--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        int dp[X + 1][Y + 200 + 1];
        for (int i = 0; i <= X; i++) {
            for (int j = -200; j <= Y + 200; j++) {
                dp[i][j + 200] = INT_MAX;
            }
        }
        dp[0][200] = 0;
        for (int i = 1; i <= X; i++) {
            for (int j = -200; j <= Y + 200; j++) {
                if (j - 2 >= -200 && dp[i - 1][j - 2 + 200] != INT_MAX) {
                    dp[i][j + 200] = min(dp[i][j + 200], dp[i - 1][j - 2 + 200] + S);
                }
                if (j - 1 >= -200 && dp[i - 1][j - 1 + 200] != INT_MAX) {
                    dp[i][j + 200] = min(dp[i][j + 200], dp[i - 1][j - 1 + 200] + G);
                }
                if (j >= -200 && dp[i - 1][j + 200] != INT_MAX) {
                    dp[i][j + 200] = min(dp[i][j + 200], dp[i - 1][j + 200] + Q);
                }
                if (j + 1 <= Y + 200 && dp[i - 1][j + 1 + 200] != INT_MAX) {
                    dp[i][j + 200] = min(dp[i][j + 200], dp[i - 1][j + 1 + 200] + R);
                }
                if (j + 2 <= Y + 200 && dp[i - 1][j + 2 + 200] != INT_MAX) {
                    dp[i][j + 200] = min(dp[i][j + 200], dp[i - 1][j + 2 + 200] + D);
                }
            }
        }
        if (dp[X][Y + 200] == INT_MAX) {
            printf("-1\n");
        } else {
            printf("%d\n", dp[X][Y + 200]);
        }
    }
    return 0;
}

