                for (int j = -200; j <= Y + 200; j++) {
                    dp[i][j + 200] = Integer.MAX_VALUE;
                }
            }
            dp[0][200] = 0;
            for (int i = 1; i <= X; i++) {
                for (int j = -200; j <= Y + 200; j++) {
                    if (j - 2 >= -200 && dp[i - 1][j - 2 + 200] != Integer.MAX_VALUE) {
                        dp[i][j + 200] = Math.min(dp[i][j + 200], dp[i - 1][j - 2 + 200] + S);
                    }
                    if (j - 1 >= -200 && dp[i - 1][j - 1 + 200] != Integer.MAX_VALUE) {
                        dp[i][j + 200] = Math.min(dp[i][j + 200], dp[i - 1][j - 1 + 200] + G);
                    }
                    if (j >= -200 && dp[i - 1][j + 200] != Integer.MAX_VALUE) {
                        dp[i][j + 200] = Math.min(dp[i][j + 200], dp[i - 1][j + 200] + Q);
                    }
                    if (j + 1 <= Y + 200 && dp[i - 1][j + 1 + 200] != Integer.MAX_VALUE) {
                        dp[i][j + 200] = Math.min(dp[i][j + 200], dp[i - 1][j + 1 + 200] + R);
                    }
                    if (j + 2 <= Y + 200 && dp[i - 1][j + 2 + 200] != Integer.MAX_VALUE) {
                        dp[i][j + 200] = Math.min(dp[i][j + 200], dp[i - 1][j + 2 + 200] + D);
                    }
                }
            }
